import json
import os

# Find all file paths stored in locals
file_paths = {}
for key, value in locals().items():
    if isinstance(value, str) and (value.endswith('.json') or '.json' in value):
        file_paths[key] = value

print('Found file paths:')
for k, v in file_paths.items():
    print(f'  {k} -> {v}')
    if os.path.exists(v):
        print(f'    File exists: {os.path.getsize(v)} bytes')
    else:
        print(f'    File does NOT exist')

# Check what keys we have
print(f'\nAll locals keys: {[k for k in locals().keys()]}')

# Try to access one of the files directly
try:
    for key, path in file_paths.items():
        if 'query_db' in key:
            with open(path, 'r') as f:
                capital_market_companies = json.load(f)
            print(f'\nLoaded {len(capital_market_companies)} capital market companies')
            break
except Exception as e:
    print(f'Error loading file: {e}')
    capital_market_companies = []

print('__RESULT__:')
print(json.dumps({
    'file_paths': file_paths,
    'companies_loaded': len(capital_market_companies) if 'capital_market_companies' in locals() else 0
}))

